    let f1 = make_fi(1, 2, hashes.clone()); // 2 lines, 20 nodes
    let f2 = make_fi(10, 11, hashes);
    let pairs = find_duplicate_pairs(&[f1, f2], 0.5, 10, 5); // min_lines=10
